$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_f7266ba0eb429463c24906863d97f74d'] = 'Υποστήριξη Joobox για αυτήν την ενότητα';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_7c590d9272ad1786e0e73357bf415267'] = 'Αυτή η δωρεάν ενότητα GitHub παρέχεται χωρίς ατομική τεχνική υποστήριξη. Η εγκατάσταση, η ρύθμιση, οι δοκιμές σε παραγωγή, οι ενημερώσεις και η αντιμετώπιση προβλημάτων είναι διαθέσιμες για πελάτες του Joobox PrestaShop Cloud ή άλλης πληρωμένης υπηρεσίας που έχει συμφωνηθεί ρητά με την JOO INTERNET MEDIA LTD.';
