$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_cf090b8fa4a136ed6058aaf84d5d2538'] = 'Τελευταίο μήνυμα';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_831c20d2063d575696365dce34a60c88'] = 'Ρυθμίσεις καθαρισμού';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_8942d7461e33e2685a59edc299ba85ac'] = 'Ενεργοποίηση καθαρισμού';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_93cba07454f06a4a960172bbd6e2a435'] = 'Ναι';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bafd7322c6e97d25b6299b5d6fe8920b'] = 'Όχι';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_83112255bb4233cad4276eab160483e8'] = 'Ενεργοποιεί ή απενεργοποιεί τον καθαριστή. Όταν είναι απενεργοποιημένος, το cron URL και το κουμπί χειροκίνητης εκτέλεσης δεν θα διαγράφουν παλιά στατιστικά. Χρησιμοποιήστε αυτόν τον διακόπτη όταν θέλετε να κρατήσετε την ενότητα εγκατεστημένη αλλά να σταματήσετε προσωρινά κάθε καθαρισμό.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Ημέρες διατήρησης στατιστικών συνδέσεων';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_b878a67f82524d412dae79ad597ff402'] = 'Οι γραμμές παλαιότερες από αυτό θα αφαιρεθούν από τα connections, connections_source και connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_5ee406d769ac3887713d3308a0d01601'] = 'Εισαγάγετε τον αριθμό ημερών για τις οποίες πρέπει να διατηρούνται τα ακατέργαστα στατιστικά επισκεπτών του PrestaShop. Παράδειγμα: 60 σημαίνει ότι η ενότητα κρατά τις τελευταίες 60 ημέρες και διαγράφει παλαιότερες εγγραφές από τα ps_connections, ps_connections_source και ps_connections_page. Μην το ορίσετε σε 1 εκτός αν είστε βέβαιοι ότι δεν χρειάζεστε πρόσφατα στατιστικά επισκεπτών.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_1300769d8d72fc8218b40772f1c25efc'] = 'Μέγεθος παρτίδας';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_631c4c75cb36e0fcee3da42ef67e730e'] = 'Μέγιστος αριθμός συνδέσεων που επεξεργάζονται σε μία παρτίδα.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_acbc6e359c79ace4ef9b5398148c13e2'] = 'Εισαγάγετε πόσες κύριες εγγραφές σύνδεσης μπορούν να επεξεργαστούν σε μία εσωτερική παρτίδα. Μικρότερες τιμές είναι ασφαλέστερες σε αδύναμο hosting αλλά απαιτούν περισσότερες εκτελέσεις cron. Μεγαλύτερες τιμές καθαρίζουν ταχύτερα αλλά μπορούν να κρατούν κλειδώματα βάσης για περισσότερο. Προτεινόμενη αρχική τιμή: 1000 έως 5000· αυξήστε μόνο μετά από δοκιμή του χρόνου εκτέλεσης.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2806977593fb4c23003cc11306b135d1'] = 'Μέγιστες παρτίδες ανά εκτέλεση';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d31a094a19379b58b63b51ef0f9d9362'] = 'Περιορίζει πόση εργασία μπορεί να κάνει μία εκτέλεση cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_e221a5a91ea62a43adc5bb15614eb578'] = 'Εισαγάγετε πόσες παρτίδες μπορούν να εκτελεστούν κατά τη διάρκεια μίας εκτέλεσης cron. Οι συνολικές πιθανές διαγραμμένες κύριες εγγραφές ανά εκτέλεση είναι περίπου Μέγεθος παρτίδας επί Μέγιστες παρτίδες ανά εκτέλεση. Παράδειγμα: 5000 και 10 σημαίνει έως περίπου 50000 κύριες εγγραφές σε μία εκτέλεση cron. Μειώστε το αν το κατάστημα επιβραδύνεται κατά τον καθαρισμό.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a1a47524ffa9c839887703df1fbe70a3'] = 'Καθαρισμός ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_924684322fe68e56ef9205e7f480f598'] = 'Καθαρίζει την cache του μπλοκ faceted/layered search με χρήση TRUNCATE TABLE. Ο πίνακας δημιουργείται ξανά κενός από MySQL/MariaDB.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Ενεργοποιήστε το μόνο αν το ps_layered_filter_block μεγαλώνει υπερβολικά ή περιέχει παλιά cache faceted search. Αυτό δεν διαγράφει προϊόντα, κατηγορίες ή τον δείκτη τιμών layered. Μετά τον καθαρισμό, το PrestaShop ή η ενότητα faceted search μπορεί να ξαναχτίσει αυτήν την cache όταν χρειαστεί.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Συγκέντρωση στατιστικών πηγών επισκεψιμότητας πριν τη διαγραφή';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Αποθηκεύει ημερήσια συνοπτικά στατιστικά πηγών επισκεψιμότητας πριν διαγράψει τις ακατέργαστες γραμμές.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Όταν είναι ενεργό, η ενότητα αποθηκεύει μια μικρή ημερήσια σύνοψη πριν αφαιρέσει τα ακατέργαστα στατιστικά PrestaShop. Κρατά μετρήσεις όπως επισκέψεις, προβολές σελίδων, domain πηγής και τιμές UTM. Δεν αποθηκεύει διευθύνσεις IP, πλήρη referrer URL ή user-agent strings. Απενεργοποιήστε το αν θέλετε μόνο διαγραφή και δεν χρειάζεστε ιστορικές περιλήψεις πηγών.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Ημέρες διατήρησης συγκεντρωτικών στατιστικών';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Πόσο καιρό πρέπει να κρατείται ο μικρός ημερήσιος συνοπτικός πίνακας.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Εισαγάγετε πόσες ημέρες οι συγκεντρωτικές περιλήψεις επισκεψιμότητας πρέπει να παραμένουν στον πίνακα της ενότητας. Παράδειγμα: 730 κρατά περίπου δύο χρόνια ημερήσιων περιλήψεων πηγών. Αυτή η ρύθμιση επηρεάζει μόνο τον πίνακα ps_jooim_dbcleaner_traffic_daily, όχι τους αρχικούς πίνακες στατιστικών του PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Χρονικό όριο παλιού κλειδώματος σε δευτερόλεπτα';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Προστασία από δύο διαδικασίες καθαρισμού που τρέχουν ταυτόχρονα.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Εισαγάγετε τον αριθμό δευτερολέπτων μετά τον οποίο ένα ημιτελές κλείδωμα καθαρισμού θεωρείται εγκαταλελειμμένο. Αυτό προστατεύει τη βάση από δύο ταυτόχρονες εκτελέσεις cron. Προτεινόμενη τιμή: 7200. Μειώστε το μόνο αν το cron είναι εγγυημένο ότι τελειώνει γρήγορα.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c9cc8cce247e49bae79f15173ce97354'] = 'Αποθήκευση';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_1b793db6c00482d633b29701c7bcb08c'] = 'Cron';
